133→fn show_both(
134→    workspace: &Workspace,
135→    repo: &Arc<ReadonlyRepo>,
136→    args: &ShowArgs,
137→    both_count: usize,
138→    file_limit: FileLimit,
139→    root_commit_id: &jj_lib::backend::CommitId,
140→) -> Result<(), Box<dyn std::error::Error>> {
141→    let bare_rev = args.pos_rev.as_deref().unwrap_or("@");
142→    let spec = common::parse_dot_rev(bare_rev);
143→    let anchor_ids = common::resolve_revset(workspace, repo, &spec.rev)?;
144→    if anchor_ids.is_empty() {
145→        return Err(format!("no commit found for revision '{}'", spec.rev).into());
146→    }
147→    let anchor_id = &anchor_ids[0];
148→
149→    let ancestor_ids = common::resolve_revset(workspace, repo, &format!("::{}", spec.rev))?;
150→    let descendant_ids = common::resolve_revset(workspace, repo, &format!("{}::", spec.rev))?;
151→
152→    // Descendants (newest first), excluding anchor
153→    let mut desc_ids: Vec<_> = descendant_ids
154→        .iter()
155→        .filter(|id| **id != *root_commit_id && **id != *anchor_id)
156→        .collect();
157→    if both_count > 0 {
158→        let start = desc_ids.len().saturating_sub(both_count);
159→        desc_ids = desc_ids[start..].to_vec();
160→    } else {
161→        desc_ids.clear();
162→    }
163→
164→    // Ancestors (newest first), excluding anchor
165→    let mut anc_ids: Vec<_> = Vec::new();
166→    if both_count > 0 {
167→        let mut c = 0;
168→        for id in &ancestor_ids {
169→            if *id == *root_commit_id || *id == *anchor_id {
170→                continue;
171→            }
172→            anc_ids.push(id);
173→            c += 1;
174→            if c >= both_count {
175→                break;
176→            }
177→        }
178→    }
179→
180→    let mut first = true;
181→    for id in &desc_ids {
182→        if !first {
183→            println!("────────────────────────────────────────");
184→        }
185→        first = false;
186→        let commit = repo.store().get_commit(id)?;
187→        show_one_commit(&commit, workspace, repo, file_limit, false)?;
188→    }
189→
190→    if !first {
191→        println!("────────────────────────────────────────");
192→    }
193→    first = false;
194→    let anchor_commit = repo.store().get_commit(anchor_id)?;
195→    show_one_commit(&anchor_commit, workspace, repo, file_limit, true)?;
196→
197→    for id in &anc_ids {
198→        if !first {
199→            println!("────────────────────────────────────────");
200→        }
201→        first = false;
202→        let commit = repo.store().get_commit(id)?;
203→        show_one_commit(&commit, workspace, repo, file_limit, false)?;
204→    }
205→
206→    Ok(())
207→}
208→
209→fn show_one_commit(
210→    commit: &Commit,
211→    workspace: &Workspace,
212→    repo: &Arc<ReadonlyRepo>,
213→    file_limit: FileLimit,
214→    is_primary: bool,
215→) -> Result<(), Box<dyn std::error::Error>> {
216→    // Ids
217→    let ids_line = common::format_commit_short(commit);
218→    if is_primary {
219→        println!("Ids:       {}", common::bold(&ids_line));
220→    } else {
221→        println!("Ids:       {ids_line}");
222→    }
223→
224→    // Author
225→    let author = commit.author();
226→    println!(
227→        "Author:    {} <{}> ({})",
228→        author.name,
229→        author.email,
230→        format_timestamp(&author.timestamp)
231→    );
232→
233→    // Committer
234→    let committer = commit.committer();
235→    println!(
236→        "Committer: {} <{}> ({})",
237→        committer.name,
238→        committer.email,
239→        format_timestamp(&committer.timestamp)
240→    );
241→
242→    // Parents
243→    let root_commit_id = repo.store().root_commit_id().clone();
244→    for parent_id in commit.parent_ids() {
245→        if *parent_id == root_commit_id {
246→            continue;
247→        }
248→        let parent = repo.store().get_commit(parent_id)?;
249→        println!("Parent:    {}", common::format_commit_short(&parent));
250→    }
251→
252→    // Children
253→    let children_ids =
254→        common::resolve_revset(workspace, repo, &format!("children({})", commit.id().hex()))?;
255→    for child_id in &children_ids {
256→        if *child_id == root_commit_id {
257→            continue;
258→        }
259→        let child = repo.store().get_commit(child_id)?;
260→        println!("Child:     {}", common::format_commit_short(&child));
261→    }
262→
263→    // Branches
264→    let branches_str = format_branches(commit, workspace, repo)?;
265→    println!("Branches:  {branches_str}");
266→
267→    // Follows
268→    let follows = find_nearest_tag(commit, workspace, repo, true)?;
269→    println!("Follows:   {}", follows.as_deref().unwrap_or(""));
270→
271→    // Precedes
272→    let precedes = find_nearest_tag(commit, workspace, repo, false)?;
273→    println!("Precedes:  {}", precedes.as_deref().unwrap_or(""));
274→
275→    // Description (body only — title is on the Ids line)
276→    print_description(commit);
277→
278→    // Changed files
279→    if file_limit != FileLimit::None {
280→        print_diff(commit, repo, file_limit)?;
281→    }
282→
283→    Ok(())
284→}
285→
286→fn find_nearest_tag(
287→    commit: &Commit,
288→    workspace: &Workspace,
289→    repo: &Arc<ReadonlyRepo>,
290→    ancestor: bool,
291→) -> Result<Option<String>, Box<dyn std::error::Error>> {
292→    let commit_hex = commit.id().hex();
293→
294→    let revset_str = if ancestor {
295→        format!("heads(tags() & ::{})", commit_hex)
296→    } else {
297→        format!("roots(tags() & {}::)", commit_hex)
298→    };
299→
300→    let tag_ids = common::resolve_revset(workspace, repo, &revset_str)?;
301→    if tag_ids.is_empty() {
302→        return Ok(None);
303→    }
304→
305→    let tag_id = &tag_ids[0];
306→    let view = repo.view();
307→    for (name, local_remote) in view.tags() {
308→        if local_remote.local_target.added_ids().any(|id| id == tag_id) {
309→            return Ok(Some(name.as_str().to_string()));
310→        }
311→    }
312→
313→    Ok(None)
314→}
315→
316→fn format_branches(
317→    commit: &Commit,
318→    workspace: &Workspace,
319→    repo: &Arc<ReadonlyRepo>,
320→) -> Result<String, Box<dyn std::error::Error>> {
321→    let commit_hex = commit.id().hex();
322→    let view = repo.view();
323→    let mut names: Vec<String> = Vec::new();
324→
325→    for (name, local_remote) in view.bookmarks() {
326→        for bookmark_id in local_remote.local_target.added_ids() {
327→            let revset_str = format!("{} & ::{}", commit_hex, bookmark_id.hex());
328→            let results = common::resolve_revset(workspace, repo, &revset_str)?;
329→            if !results.is_empty() {
330→                names.push(name.as_str().to_string());
331→                break;
332→            }
333→        }
334→
335→        for (remote_name, remote_ref) in &local_remote.remote_refs {
336→            if remote_name.as_str() == "git" {
337→                continue;
338→            }
339→            for bookmark_id in remote_ref.target.added_ids() {
340→                let revset_str = format!("{} & ::{}", commit_hex, bookmark_id.hex());
341→                let results = common::resolve_revset(workspace, repo, &revset_str)?;
342→                if !results.is_empty() {
343→                    names.push(format!("{}@{}", name.as_str(), remote_name.as_str()));
344→                    break;
345→                }
346→            }
347→        }
348→    }
349→
350→    Ok(names.join(", "))
351→}
