353→fn format_timestamp(ts: &jj_lib::backend::Timestamp) -> String {
354→    let millis = ts.timestamp.0;
355→    let secs = millis / 1000;
356→    let tz_minutes = ts.tz_offset;
357→
358→    let dt = chrono::DateTime::from_timestamp(secs, 0)
359→        .unwrap_or_default()
360→        .with_timezone(
361→            &chrono::FixedOffset::east_opt(tz_minutes * 60).unwrap_or(chrono::Utc.fix()),
362→        );
363→
364→    dt.format("%Y-%m-%d %H:%M:%S").to_string()
365→}
