367→fn print_description(commit: &Commit) {
368→    let desc = commit.description();
369→    let body: String = desc
370→        .lines()
371→        .skip(1)
372→        .skip_while(|l| l.is_empty())
373→        .collect::<Vec<_>>()
374→        .join("\n");
375→
376→    println!("Description:");
377→    for line in body.lines() {
378→        println!("    {line}");
379→    }
380→}
