211→/// Indent all lines after the first by `n` spaces.
212→///
213→/// Returns the string unchanged if `n == 0` or there is only one line.
214→pub fn indent_body(s: &str, n: usize) -> String {
215→    if n == 0 {
216→        return s.to_string();
217→    }
218→    let pad = " ".repeat(n);
219→    let mut lines = s.lines();
220→    let mut result = match lines.next() {
221→        Some(first) => first.to_string(),
222→        None => return String::new(),
223→    };
224→    for line in lines {
225→        result.push('\n');
226→        if !line.is_empty() {
227→            result.push_str(&pad);
228→        }
229→        result.push_str(line);
230→    }
231→    result
232→}
