        .iter()
        .filter(|id| **id != *root_commit_id && **id != *anchor_id)
        .collect();
    if both_count > 0 {
        let start = desc_ids.len().saturating_sub(both_count);
        desc_ids = desc_ids[start..].to_vec();
    } else {
