use std::path::PathBuf;
use std::sync::Arc;

use chrono::Offset;
use clap::Args;
use jj_lib::backend::TreeValue;
use jj_lib::commit::Commit;
use jj_lib::matchers::EverythingMatcher;
use jj_lib::merged_tree::TreeDiffIterator;
use jj_lib::object_id::ObjectId;
use jj_lib::repo::{ReadonlyRepo, Repo};
use jj_lib::workspace::Workspace;
use pollster::FutureExt;

use crate::common;

/// Parsed file limit: None (suppress), Some(n) (cap at n), or all.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum FileLimit {
    /// Don't show changed files section at all.
    None,
    /// Show up to N files (with first/last split if truncated).
    Cap(usize),
    /// Show all files.
    All,
}

impl FileLimit {
    fn parse(s: &str) -> Result<Self, String> {
        match s {
            "0" => Ok(FileLimit::None),
            "all" => Ok(FileLimit::All),
            _ => s
                .parse::<usize>()
                .map(FileLimit::Cap)
                .map_err(|_| format!("invalid file limit '{s}': expected number, 0, or 'all'")),
        }
    }
}

#[derive(Args, Debug)]
pub struct ShowArgs {
    /// Revision (with optional .. notation)
    #[arg()]
    pub pos_rev: Option<String>,

    /// Count (commits per dotted side)
    #[arg()]
    pub pos_count: Option<usize>,

    /// Revision to show (default: @)
    #[arg(short, long, default_value = "@")]
    pub revision: String,

    /// Max changed files: number, 0 (none), or 'all' (default: 50)
    #[arg(short = 'f', long = "files", default_value = "50")]
    pub files: String,

    /// Maximum number of commits to show
    #[arg(short, long)]
    pub limit: Option<usize>,

    /// Path to jj repo (default: current directory)
    #[arg(short = 'R', long, default_value = ".")]
    pub repo: PathBuf,
}

pub fn show(args: &ShowArgs) -> Result<(), Box<dyn std::error::Error>> {
    let file_limit = FileLimit::parse(&args.files)?;

    let (workspace, repo) = common::load_repo(&args.repo)?;

    // Parse dot notation and map to collect_ids params
    let flag_rev_set = args.revision != "@";
    let bare_rev = args.pos_rev.as_deref().unwrap_or("@");
    let spec = common::parse_dot_rev(bare_rev);

    let (rev, desc_count, anc_count) = if flag_rev_set {
        // Flag override: just show the specified revision
        (args.revision.as_str(), Some(0), args.limit.or(Some(0)))
    } else {
        match spec.direction {
            common::DotDirection::None => {
                let count = args.pos_count.or(args.limit);
                (&*spec.rev, Some(0), count.or(Some(0)))
            }
            common::DotDirection::Ancestors => {
                let count = args.pos_count.or(args.limit);
                (&*spec.rev, Some(0), count)
            }
            common::DotDirection::Descendants => {
                let count = args.pos_count.or(args.limit);
                (&*spec.rev, count, Some(0))
            }
            common::DotDirection::Both => {
                let count = args.pos_count.or(args.limit).or(Some(0));
                (&*spec.rev, count, count)
            }
        }
    };

    let (ids, anchor_index) = common::collect_ids(&workspace, &repo, rev, desc_count, anc_count)?;

    let mut first = true;
    for (i, commit_id) in ids.iter().enumerate() {
        if !first {
            println!("────────────────────────────────────────");
        }
        first = false;

        let commit = repo.store().get_commit(commit_id)?;
        show_one_commit(&commit, &workspace, &repo, file_limit, i == anchor_index)?;
    }

    Ok(())

