    if flag_rev_set {
        // Flag override: just show the specified revision
        spec.rev = args.revision.clone();
        spec.desc_count = Some(0);
        spec.anc_count = args.limit.or(Some(0));
    } else {
        let count = args.pos_count.or(args.limit);
        // Apply count to open (None) sides; closed sides stay at Some(0)
        if let Some(c) = count {
            if spec.desc_count.is_none() {
                spec.desc_count = Some(c);
            }
            if spec.anc_count.is_none() {
                spec.anc_count = Some(c);
            }
        }
        // bare `x 5` → treat as `x.. 5` (ancestors)
        if spec.desc_count == Some(0) && spec.anc_count == Some(0) {
            if let Some(c) = count {
                spec.anc_count = Some(c);
            }
        }
    }

    let (ids, anchor_index) = common::collect_ids(&workspace, &repo, rev, desc_count, anc_count)?;

    let mut first = true;
    for (i, commit_id) in ids.iter().enumerate() {
        if !first {
            println!("────────────────────────────────────────");
        }
        first = false;

        let commit = repo.store().get_commit(commit_id)?;
        show_one_commit(&commit, &workspace, &repo, file_limit, i == anchor_index)?;
    }

    Ok(())
}

