    } else {
        println!("Changed files: {total}, showing first {cap}");
        for line in &lines[..cap] {
            println!("{line}");
        }
    }

    Ok(())
}

fn file_type_str(value: &TreeValue) -> &'static str {
    match value {
        TreeValue::File {
            executable: false, ..
        } => "regular file",
        TreeValue::File {
            executable: true, ..
        } => "executable file",
        TreeValue::Symlink(_) => "symlink",
        TreeValue::Tree(_) => "tree",
        TreeValue::GitSubmodule(_) => "git submodule",
