/// Result of parsing positional `..` notation.
///
/// Counts are `Some(0)` for closed sides and `None` for open (dotted) sides.
/// Open sides become unlimited unless a positional count is applied later.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct DotSpec {
    /// The bare revision (without `..`).
    pub rev: String,
    /// Descendant count: `None` = open (dotted), `Some(0)` = closed.
    pub desc_count: Option<usize>,
    /// Ancestor count: `None` = open (dotted), `Some(0)` = closed.
    pub anc_count: Option<usize>,
}

/// Parse a positional REV string for `..` notation.
///
/// Returns the bare revision with open/closed counts per side.
/// `None` means the side had dots (open for expansion);
/// `Some(0)` means no dots on that side (closed).
/// Actual counts are applied later from positional args.
pub fn parse_dot_rev(rev: &str) -> DotSpec {
    if let Some(inner) = rev.strip_prefix("..").and_then(|s| s.strip_suffix("..")) {
        DotSpec {
            rev: inner.to_string(),
            desc_count: None,
            anc_count: None,
        }
    } else if let Some(inner) = rev.strip_prefix("..") {
        DotSpec {
            rev: inner.to_string(),
            desc_count: None,
            anc_count: Some(0),
        }
    } else if let Some(inner) = rev.strip_suffix("..") {
        DotSpec {
            rev: inner.to_string(),
            desc_count: Some(0),
            anc_count: None,
        }
    } else {
        DotSpec {
            rev: rev.to_string(),
            desc_count: Some(0),
            anc_count: Some(0),
        }
    }
}

/// Resolve effective revision, limit, and whether results need reversing
/// from positional args combined with named flags.
///
/// Named flags (`-r`, `-l`) take precedence over positional args.
pub struct ResolvedArgs {
    /// The jj revset string to evaluate.
    pub revset: String,
    /// Maximum number of commits to return (None = unlimited).
    pub limit: Option<usize>,
    /// For `..x..`, the count per side.
    pub both_count: Option<usize>,
    /// The bare primary revision (for highlighting).
    pub primary_rev: String,
}

/// Resolve positional `..` args with named flag overrides.
///
/// - `pos_rev`: first positional arg (may contain `..`)
/// - `pos_count`: second positional arg
/// - `flag_rev`: `-r` flag value (if different from default)
/// - `flag_limit`: `-l` flag value
/// - `default_rev`: the default revision (e.g. "@")
pub fn resolve_dot_args(
    pos_rev: Option<&str>,
    pos_count: Option<usize>,
    flag_rev: &str,
    flag_limit: Option<usize>,
    default_rev: &str,
) -> ResolvedArgs {
    // If named flags were explicitly set, they take full precedence
    let flag_rev_set = flag_rev != default_rev;
    let flag_limit_set = flag_limit.is_some();

    if flag_rev_set || (flag_limit_set && pos_rev.is_none()) {
        return ResolvedArgs {
            revset: flag_rev.to_string(),
            limit: flag_limit,
            both_count: None,
            primary_rev: flag_rev.to_string(),
        };
    }

    // Use positional args
    let rev_str = pos_rev.unwrap_or(default_rev);
    let mut spec = parse_dot_rev(rev_str);

    // Apply positional count to open (None) sides
    // Count always means total including anchor, so subtract 1 per open side
    if let Some(c) = pos_count {
        let n = c.saturating_sub(1);
        if spec.desc_count.is_none() {
            spec.desc_count = Some(n);
        }
        if spec.anc_count.is_none() {
            spec.anc_count = Some(n);
        }
        // bare `x 5` → treat as `x.. 5` (ancestors)
        if spec.desc_count == Some(0) && spec.anc_count == Some(0) {
            spec.anc_count = Some(n);
        }
    }

    // Named limit overrides positional count on open sides
    if flag_limit_set {
        let l = flag_limit.unwrap();
        let n = l.saturating_sub(1);
        // Apply to whichever sides were originally open (dotted)
        let orig = parse_dot_rev(rev_str);
        if orig.desc_count.is_none() {
            spec.desc_count = Some(n);
        }
        if orig.anc_count.is_none() {
            spec.anc_count = Some(n);
        }
        // bare rev with -l → ancestors
        if orig.desc_count == Some(0) && orig.anc_count == Some(0) {
            spec.anc_count = Some(n);
        }
    }

    let primary = spec.rev.clone();
    let is_both = spec.desc_count.is_some()
        && spec.desc_count != Some(0)
        && spec.anc_count.is_some()
        && spec.anc_count != Some(0);

    if is_both {
        // Both directions have counts — use both_count path
        let count = spec.desc_count.unwrap(); // desc == anc for ..x.. currently
        ResolvedArgs {
            revset: format!("::{}|{}::", spec.rev, spec.rev),
            limit: None,
            both_count: Some(count),
            primary_rev: primary,
        }
    } else if spec.desc_count == Some(0) && spec.anc_count == Some(0) {
        // No dots, no count — single revision
        ResolvedArgs {
            revset: spec.rev,
            limit: Some(1),
            both_count: None,
            primary_rev: primary,
        }
    } else if spec.desc_count == Some(0) {
        // Ancestors only (x.. or bare with count)
        let limit = spec.anc_count.map(|c| c + 1); // +1 for anchor
        ResolvedArgs {
            revset: format!("::{}", spec.rev),
            limit,
            both_count: None,
            primary_rev: primary,
        }
    } else {
        // Descendants only (..x)
        let limit = spec.desc_count.map(|c| c + 1); // +1 for anchor
        ResolvedArgs {
            revset: format!("{}::", spec.rev),
            limit,
            both_count: None,
            primary_rev: primary,
        }
    }
}

/// Wrap text in ANSI bold escape codes.
pub fn bold(s: &str) -> String {
    format!("\x1b[1m{s}\x1b[0m")
}

/// Bold only the first line of a multi-line string.
pub fn bold_first_line(s: &str) -> String {
    if let Some(pos) = s.find('\n') {
        format!("\x1b[1m{}\x1b[0m{}", &s[..pos], &s[pos..])
    } else {
        bold(s)
    }
}

/// Indent all lines after the first by `n` spaces.
///
/// Returns the string unchanged if `n == 0` or there is only one line.
pub fn indent_body(s: &str, n: usize) -> String {
    if n == 0 {
        return s.to_string();
    }
    let pad = " ".repeat(n);
    let mut lines = s.lines();
    let mut result = match lines.next() {
        Some(first) => first.to_string(),
        None => return String::new(),
    };
    for line in lines {
        result.push('\n');
        if !line.is_empty() {
            result.push_str(&pad);
        }
        result.push_str(line);
    }
    result
}

/// Format: just the short changeID.
pub fn format_chid(commit: &Commit) -> String {
    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
    change_hex[..change_hex.len().min(12)].to_string()
}

/// Format: changeID commitID first-line (single line).
pub fn format_commit_short(commit: &Commit) -> String {
    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
    let change_short = &change_hex[..change_hex.len().min(12)];
    let commit_hex = commit.id().hex();
    let commit_short = &commit_hex[..commit_hex.len().min(12)];
    let first_line = commit.description().lines().next().unwrap_or("");
    if first_line.is_empty() {
        format!("{change_short} {commit_short} (no description set)")
    } else {
        format!("{change_short} {commit_short} {first_line}")
    }
}

/// Format: changeID commitID first-line, then remaining description lines.
pub fn format_commit_full(commit: &Commit) -> String {
    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
    let change_short = &change_hex[..change_hex.len().min(12)];
    let commit_hex = commit.id().hex();
    let commit_short = &commit_hex[..commit_hex.len().min(12)];
    let desc = commit.description();
    if desc.is_empty() {
        format!("{change_short} {commit_short} (no description set)")
    } else {
        let mut lines = desc.lines();
        let first_line = lines.next().unwrap_or("");
        let mut result = format!("{change_short} {commit_short} {first_line}");
        for line in lines {
            result.push('\n');
            result.push_str(line);
        }
        result
    }
}

/// Collect commit IDs for `..x..` (both directions) or any dot notation.
///
/// Returns `(commit_ids, anchor_index)` — the IDs in display order
/// (descendants closest to anchor, anchor, ancestors closest to anchor)
/// and the index of the anchor commit within the list.
///
/// - `desc_count`: `Some(n)` = n closest descendants, `None` = all, `Some(0)` = none
/// - `anc_count`: `Some(n)` = n closest ancestors, `None` = all, `Some(0)` = none
pub fn collect_ids(
    workspace: &Workspace,
    repo: &Arc<ReadonlyRepo>,
    rev: &str,
    desc_count: Option<usize>,
    anc_count: Option<usize>,
) -> Result<(Vec<CommitId>, usize), Box<dyn std::error::Error>> {
    let anchor_ids = resolve_revset(workspace, repo, rev)?;
    if anchor_ids.is_empty() {
        return Err(format!("no commit found for revision '{rev}'").into());
    }
    let anchor_id = &anchor_ids[0];
    let root_commit_id = repo.store().root_commit_id().clone();

    // Descendants (closest to anchor)
    let mut desc_ids: Vec<CommitId> = Vec::new();
    if desc_count != Some(0) {
        let descendant_ids = resolve_revset(workspace, repo, &format!("{rev}::"))?;
        desc_ids = descendant_ids
            .into_iter()
            .filter(|id| *id != root_commit_id && *id != *anchor_id)
            .collect();
        if let Some(n) = desc_count {
            let start = desc_ids.len().saturating_sub(n);
            desc_ids = desc_ids[start..].to_vec();
        }
    }

    // Ancestors (closest to anchor)
    let mut anc_ids: Vec<CommitId> = Vec::new();
    if anc_count != Some(0) {
        let ancestor_ids = resolve_revset(workspace, repo, &format!("::{rev}"))?;
        let limit = anc_count.unwrap_or(usize::MAX);
        let mut count = 0;
        for commit_id in ancestor_ids {
            if commit_id == root_commit_id || commit_id == *anchor_id {
                continue;
            }
            anc_ids.push(commit_id);
            count += 1;
            if count >= limit {
                break;
            }
        }
    }

    let anchor_index = desc_ids.len();
    let mut result = desc_ids;
    result.push(anchor_id.clone());
    result.extend(anc_ids);
    Ok((result, anchor_index))
}

/// Collect formatted lines for `..x..` (both directions).
///
/// `formatter` converts a `Commit` into a display string.
/// Returns `(lines, anchor_index)` — the lines in display order
/// (descendants newest first, anchor, ancestors newest first)
/// and the index of the anchor commit within the lines.
pub fn collect_commit_lines<F>(
    repo: &Arc<ReadonlyRepo>,
    repo_path: &Path,
    pos_rev: Option<&str>,
    both_count: usize,
    formatter: F,
) -> Result<(Vec<String>, usize), Box<dyn std::error::Error>>
where
    F: Fn(&Commit) -> String,
{
    let bare_rev = pos_rev.unwrap_or("@");
    let spec = parse_dot_rev(bare_rev);
    let (workspace, _) = load_repo(repo_path)?;
    let count = if both_count > 0 {
        Some(both_count)
    } else {
        Some(0)
    };
    let (ids, anchor_index) = collect_ids(&workspace, repo, &spec.rev, count, count)?;
    let lines: Vec<String> = ids
        .iter()
        .map(|id| {
            let commit = repo.store().get_commit(id)?;
            Ok(formatter(&commit))
        })
        .collect::<Result<_, Box<dyn std::error::Error>>>()?;
    Ok((lines, anchor_index))
}

pub fn load_repo(
    path: &Path,
) -> Result<(Workspace, Arc<ReadonlyRepo>), Box<dyn std::error::Error>> {
    let config = StackedConfig::with_defaults();
    let settings = UserSettings::from_config(config)?;
    let store_factories = StoreFactories::default();
    let working_copy_factories = default_working_copy_factories();

    let workspace = Workspace::load(&settings, path, &store_factories, &working_copy_factories)?;
    let repo = workspace.repo_loader().load_at_head().block_on()?;

    Ok((workspace, repo))
}

/// Parse and evaluate a revset string, returning commit IDs.
pub fn resolve_revset(
    workspace: &Workspace,
    repo: &Arc<ReadonlyRepo>,
    revset_str: &str,
) -> Result<Vec<CommitId>, Box<dyn std::error::Error>> {
    let aliases_map = RevsetAliasesMap::new();
    let fileset_aliases_map = FilesetAliasesMap::new();
    let extensions = RevsetExtensions::default();
    let workspace_root = workspace.workspace_root().to_path_buf();
    let path_converter = RepoPathUiConverter::Fs {
        cwd: workspace_root.clone(),
        base: workspace_root,
    };
    let workspace_name = workspace.workspace_name();
    let workspace_ctx = RevsetWorkspaceContext {
        path_converter: &path_converter,
        workspace_name,
    };
    let context = RevsetParseContext {
        aliases_map: &aliases_map,
        local_variables: HashMap::new(),
        user_email: "",
        date_pattern_context: chrono::Utc::now().fixed_offset().into(),
        default_ignored_remote: None,
        fileset_aliases_map: &fileset_aliases_map,
        use_glob_by_default: false,
        extensions: &extensions,
        workspace: Some(workspace_ctx),
    };

    let mut diagnostics = RevsetDiagnostics::new();
    let expression = jj_lib::revset::parse(&mut diagnostics, revset_str, &context)?;

    let no_extensions: &[Box<dyn jj_lib::revset::SymbolResolverExtension>] = &[];
    let symbol_resolver = SymbolResolver::new(repo.as_ref(), no_extensions);
    let resolved = expression.resolve_user_expression(repo.as_ref(), &symbol_resolver)?;
    let revset = resolved.evaluate(repo.as_ref())?;

    let mut commit_ids = Vec::new();
    for result in revset.iter() {
        commit_ids.push(result?);
    }
    Ok(commit_ids)
}

