    fn parse_dot_rev_both_changeid() {
        let spec = parse_dot_rev("..abcd..");
        assert_eq!(spec.rev, "abcd");
        assert_eq!(spec.desc_count, None);
        assert_eq!(spec.anc_count, None);
    }

    #[test]
    fn resolve_defaults() {
        let r = resolve_dot_args(None, None, "@", None, "@");
        assert_eq!(r.revset, "@");
        assert_eq!(r.limit, Some(1));
        assert!(r.both_count.is_none());
        assert_eq!(r.primary_rev, "@");
    }

    #[test]
    fn resolve_bare_rev_with_count() {
        let r = resolve_dot_args(Some("@"), Some(5), "@", None, "@");
        assert_eq!(r.revset, "::@");
        assert_eq!(r.limit, Some(5)); // 5 total (anchor + 4 ancestors)
    }

    #[test]
    fn resolve_ancestors() {
        let r = resolve_dot_args(Some("@.."), Some(3), "@", None, "@");
        assert_eq!(r.revset, "::@");
        assert_eq!(r.limit, Some(3)); // 3 total (anchor + 2 ancestors)
    }

    #[test]
    fn resolve_descendants() {
        let r = resolve_dot_args(Some("..@"), Some(3), "@", None, "@");
        assert_eq!(r.revset, "@::");
        assert_eq!(r.limit, Some(3)); // 3 total (2 descendants + anchor)
    }

    #[test]
    fn resolve_both() {
        let r = resolve_dot_args(Some("..@.."), Some(3), "@", None, "@");
        assert_eq!(r.revset, "::@|@::");
        assert!(r.limit.is_none());
        assert_eq!(r.both_count, Some(2)); // 3 - 1 = 2 per side
    }

    #[test]
    fn resolve_flag_overrides_positional() {
        let r = resolve_dot_args(Some("@.."), Some(5), "@-", None, "@");
        assert_eq!(r.revset, "@-"); // flag_rev takes precedence
    }

    #[test]
    fn resolve_ancestors_no_count() {
        let r = resolve_dot_args(Some("@.."), None, "@", None, "@");
        assert_eq!(r.revset, "::@");
        assert!(r.limit.is_none()); // no count, no limit
    }

    #[test]
    fn indent_body_zero() {
        let s = "first\nsecond\nthird";
        assert_eq!(indent_body(s, 0), s);
    }

    #[test]
    fn indent_body_single_line() {
        assert_eq!(indent_body("only", 3), "only");
    }

    #[test]
    fn indent_body_multi_line() {
        let s = "first\nsecond\nthird";
        assert_eq!(indent_body(s, 3), "first\n   second\n   third");
    }

    #[test]
    fn indent_body_empty_lines_preserved() {
        let s = "first\n\nthird";
        assert_eq!(indent_body(s, 3), "first\n\n   third");
    }

    #[test]
    fn indent_body_empty_string() {
        assert_eq!(indent_body("", 3), "");
    }

    #[test]
    fn resolve_flag_limit_overrides_pos_count() {
        let r = resolve_dot_args(Some("@.."), Some(5), "@", Some(3), "@");
        assert_eq!(r.revset, "::@");
        assert_eq!(r.limit, Some(3)); // flag limit 3 total (anchor + 2 ancestors)
    }
