133→///
134→/// - `pos_rev`: first positional arg (may contain `..`)
135→/// - `pos_count`: second positional arg
136→/// - `flag_rev`: `-r` flag value (if different from default)
137→/// - `flag_limit`: `-l` flag value
138→/// - `default_rev`: the default revision (e.g. "@")
139→pub fn resolve_dot_args(
140→    pos_rev: Option<&str>,
141→    pos_count: Option<usize>,
142→    flag_rev: &str,
143→    flag_limit: Option<usize>,
144→    default_rev: &str,
145→) -> ResolvedArgs {
